// Loop over input items and transform the structure
const transformedItems = [];

for (const item of $input.all()) {
  // Create the new structure with text and voice_id fields
  transformedItems.push({
    text: item.json.Input,
    voice_id: item.json["Voice ID"]
  });
}

// Store the result in a variable
const result = transformedItems;

return [{ json: { podcast: result } }];
